INSERT INTO `v1_266cebc049b7f3e0e0caf15c93c3090c61c5d62a16456bbc003883ee2935f8fa` VALUES (0, 0, 1, 0, 10, 1, "アオイさんですよね～っ！？\nグランドリームパークへようこそっ♪\n本日はおひとりさまですますか？", 5146066, 130911, 11, 66032);
